1	//===- BytecodeGen.cpp - CUDA Tile dialect bytecode generator ---*- C++ -*-===//
2	//
3	// Part of the CUDA Tile IR project, under the Apache License v2.0 with LLVM
4	// Exceptions. See https://llvm.org/LICENSE.txt for license information.
5	//
6	// SPDX-License-Identifier: Apache-2.0 WITH LLVM-exception
7	//
8	//===----------------------------------------------------------------------===//
9	//
10	// This file defines the TableGen backend for generating bytecode
11	// reader/writer functions for cuda_tile operations.
12	//
13	//===----------------------------------------------------------------------===//
14	
15	#include "mlir/TableGen/AttrOrTypeDef.h"
16	#include "mlir/TableGen/GenInfo.h"
17	
18	#include "llvm/ADT/DenseMap.h"
19	#include "llvm/ADT/DenseSet.h"
20	#include "llvm/ADT/StringRef.h"
21	#include "llvm/Support/Format.h"
22	#include "llvm/Support/FormatVariadic.h"
23	#include "llvm/TableGen/Error.h"
24	#include "llvm/TableGen/TableGenBackend.h"
25	
26	#include "BytecodeAttrAnalysis.h"
27	#include "BytecodeAttrCodeGen.h"
28	#include "BytecodeGenUtilities.h"
29	#include "BytecodeTypeAnalysis.h"
30	#include "BytecodeTypeCodeGen.h"
31	#include <map>
32	
33	using namespace llvm;
34	using namespace mlir;
35	using namespace mlir::tblgen;
36	
37	/// Reads an OpcodeRange definition from TableGen records.
38	/// Returns {minValue, maxValue} or nullopt if not defined.
39	static std::optional<std::pair<unsigned, unsigned>>
40	getOpcodeRange(const RecordKeeper &records, StringRef name) {
41	  const Record *def = records.getDef(name);
42	  if (!def)
43	    return std::nullopt;
44	  return std::make_pair(static_cast<unsigned>(def->getValueAsInt("minValue")),
45	                        static_cast<unsigned>(def->getValueAsInt("maxValue")));
46	}
47	
48	/// Validates that all CudaTileOpDef operations have bytecode opcode
49	/// assignments.
50	static void validateAllOperationsHaveOpcodes(
51	    const RecordKeeper &records,
52	    const llvm::DenseSet<StringRef> &opsWithOpcodes) {
53	  for (const Record *opDef :
54	       records.getAllDerivedDefinitions("CudaTileOpDef")) {
55	    if (!opsWithOpcodes.count(opDef->getName()))
56	      PrintFatalError(opDef->getLoc(),
57	                      "operation '" + Operator(opDef).getOperationName() +
58	                          "' is missing BytecodeOpcode assignment");
59	  }
60	}
61	
62	/// Validates all opcode assignments for consistency and correctness.
63	/// Checks:
64	/// - Opcode values are within designated ranges for each opcode class.
65	/// - No duplicate opcode values across all assignments.
66	/// - No duplicate operation assignments.
67	/// - Opcode class matches operation type.
68	static void
69	validateAllOpcodeAssignments(const RecordKeeper &records,
70	                             ArrayRef<const Record *> opcodeRecords) {
71	  // Track seen opcode values and operations to detect duplicates.
72	  llvm::DenseMap<unsigned, const Record *> seenOpcodes;
73	  llvm::DenseMap<StringRef, const Record *> seenOperations;
74	  llvm::DenseSet<StringRef> opsWithOpcodes;
75	
76	  for (const Record *record : opcodeRecords) {
77	    const Record *opRecord = record->getValueAsDef("operation");
78	    unsigned opcodeValue = record->getValueAsInt("opcodeValue");
79	    StringRef opName = opRecord->getName();
80	
81	    // Check for duplicate opcode values.
82	    if (auto it = seenOpcodes.find(opcodeValue); it != seenOpcodes.end()) {
83	      PrintFatalError(
84	          record->getLoc(),
85	          "duplicate opcode value 0x" + llvm::utohexstr(opcodeValue) +
86	              " - already assigned to operation in " + it->second->getName());
87	    }
88	    seenOpcodes[opcodeValue] = record;
89	
90	    // Check for duplicate operation assignments.
91	    if (auto it = seenOperations.find(opName); it != seenOperations.end()) {
92	      PrintFatalError(record->getLoc(),
93	                      "operation '" + opName +
94	                          "' has multiple opcode assignments - already "
95	                          "assigned in " +
96	                          it->second->getName());
97	    }
98	    seenOperations[opName] = record;
99	    opsWithOpcodes.insert(opName);
100	
101	    // Validate opcode ranges and operation type consistency.
102	    if (record->isSubClassOf("PublicOpcode")) {
103	      auto publicRange = getOpcodeRange(records, "PublicOpcodeRange");
104	      auto testingRange = getOpcodeRange(records, "TestingOpcodeRange");
105	
106	      // Public opcodes must be in public range or testing range.
107	      auto inRange = [&](auto &range) {
108	        return range && opcodeValue >= range->first &&
109	               opcodeValue <= range->second;
110	      };
111	
112	      if (!inRange(publicRange) && !inRange(testingRange)) {
113	        std::string rangeMsg = "PublicOpcode value 0x" +
114	                               llvm::utohexstr(opcodeValue) +
115	                               " is out of range (must be ";
116	        if (publicRange)
117	          rangeMsg += "0x" + llvm::utohexstr(publicRange->first) + " - 0x" +
118	                      llvm::utohexstr(publicRange->second);
119	        if (publicRange && testingRange)
120	          rangeMsg += " or ";
121	        if (testingRange)
122	          rangeMsg += ">= 0x" + llvm::utohexstr(testingRange->first);
123	        rangeMsg += ")";
124	        PrintFatalError(record->getLoc(), rangeMsg);
125	      }
126	
127	      // Testing operation validation.
128	      if (testingRange && records.getClass("CudaTileTestingOpDef")) {
129	        bool inTestingRange = opcodeValue >= testingRange->first;
130	        // Testing operations must use testing opcode range.
131	        if (opRecord->isSubClassOf("CudaTileTestingOpDef")) {
132	          if (!inTestingRange)
133	            PrintFatalError(record->getLoc(),
134	                            "Testing operation '" + opName +
135	                                "' must use testing opcode range (>= 0x" +
136	                                llvm::utohexstr(testingRange->first) +
137	                                "), but has opcode 0x" +
138	                                llvm::utohexstr(opcodeValue));
139	        } else {
140	          // Non-testing operations must not use testing opcode range.
141	          if (inTestingRange)
142	            PrintFatalError(record->getLoc(),
143	                            "Non-testing operation '" + opName +
144	                                "' cannot use testing opcode range (>= 0x" +
145	                                llvm::utohexstr(testingRange->first) +
146	                                "). This range is reserved for testing.");
147	        }
148	      }
149	    }
150	
151	  }
152	
153	  // Validate all operations have opcode assignments.
154	  validateAllOperationsHaveOpcodes(records, opsWithOpcodes);
155	}
