400	/// Helper function to generate common attribute serialization logic.
401	static void generateAttributeSerializationLogic(raw_ostream &os,
402	                                                StringRef getterName,
403	                                                StringRef attrName,
404	                                                StringRef indent = "  ") {
405	  os << llvm::formatv(R"({0}auto nativeAttrValue_{1} = op.{2}();
406	{0}if (failed(writeOpAttribute(op.getOperation(), "{1}", nativeAttrValue_{1}, writer, typeMgr, constMgr, strMgr)))
407	{0}  return failure();
408	)",
409	                      indent, attrName, getterName);
410	}
