412	/// Helper function to generate common operand serialization logic.
413	static void generateOperandSerializationLogic(raw_ostream &os, unsigned index,
414	                                              bool isOptional,
415	                                              bool isVariadic) {
416	  if (isOptional) {
417	    os << llvm::formatv(R"(
418	  if (!operandGroup_{0}.empty())
419	    writeOperands(operandGroup_{0}, writer, /*encodeSize=*/false);
420	)",
421	                        index);
422	  } else {
423	    os << llvm::formatv("  writeOperands(op.getODSOperands({0}), writer, "
424	                        "/*encodeSize=*/{1});\n",
425	                        index, isVariadic ? "true" : "false");
426	  }
427	}
