537	/// Generate result serialization without version checking.
538	static void generateSimpleResultSerialization(const Operator &op,
539	                                              raw_ostream &os) {
540	  // Track how many results are serialized.
541	  os << "  size_t numSerializedResults = op->getNumResults();\n";
542	
543	  // If the op has variadic results, write the actual number of results.
544	  if (op.isVariadic())
545	    os << "  writer.writeVarInt(op->getNumResults());\n";
546	
547	  // Write the result types of the operation.
548	  os << "  if (failed(writeResultTypes(op, writer, typeMgr)))\n"
549	     << "    return failure();\n\n";
550	}
551	
552	/// Generate version-aware result serialization.
553	static void generateVersionAwareResultSerialization(const Operator &op,
554	                                                    raw_ostream &os) {
555	  os << "  // Public operations: version checking for results.\n";
556	
557	  std::string opVersion = extractVersionFromOperation(op);
558	
559	  // Single analysis pass - collect version info for all results.
560	  SmallVector<ResultVersionInfo> versionInfos;
561	  bool hasVersionedResults = false;
562	
563	  for (int i = 0; i < op.getNumResults(); ++i) {
564	    ResultVersionInfo info(i, op.getResult(i), op, opVersion);
565	    if (info.requiresVersionCheck)
566	      hasVersionedResults = true;
567	    versionInfos.push_back(std::move(info));
568	  }
569	
570	  if (!hasVersionedResults) {
571	    // All results from original operation - use simple serialization.
572	    generateSimpleResultSerialization(op, os);
573	    return;
574	  }
575	
576	  // Usage validation, counting, and type collection in single phase.
577	  os << llvm::formatv(R"(
578	  uint64_t compatibleResults = 0;
579	  SmallVector<Type> compatibleResultTypes;
580	)");
581	
582	  for (int i = 0; i < op.getNumResults(); ++i) {
583	    const auto &info = versionInfos[i];
584	
585	    if (!info.requiresVersionCheck) {
586	      // Original result always compatible.
587	      os << llvm::formatv(R"(
588	  ++compatibleResults;
589	  compatibleResultTypes.push_back(op->getResult({0}).getType());
590	)",
591	                          i);
592	    } else {
593	      std::string version = info.majorStr + "." + info.minorStr;
594	      os << llvm::formatv(R"(
595	  auto requiredVersionFor_result_{0} = BytecodeVersion::fromVersion({1}, {2}, 0);
596	  assert(requiredVersionFor_result_{0} && "TableGen should guarantee valid versions");
597	  if (config.bytecodeVersion >= *requiredVersionFor_result_{0}) {{
598	    ++compatibleResults;
599	    compatibleResultTypes.push_back(op->getResult({3}).getType());
600	  } else {{
601	    Value resultValue = op->getResult({3});
602	    if (!resultValue.getUsers().empty()) {{
603	      op.emitError() << "result '{0}' requires bytecode version {4} but is being used and targeting "
604	                     << config.bytecodeVersion.toString()
605	                     << ". Cannot serialize to older bytecode version when newer features are used.";
606	      return failure();
607	    }
608	  }
609	)",
610	                          info.name, info.majorStr, info.minorStr, i, version);
611	    }
612	  }
613	
614	  if (op.isVariadic())
615	    os << "  writer.writeVarInt(compatibleResults);\n";
616	
617	  // Write compatible result types.
618	  os << "  if (failed(writeResultTypes(compatibleResultTypes, writer, "
619	        "typeMgr)))\n"
620	     << "    return failure();\n";
621	
622	  // Track number of serialized results for valueIndexMap updates.
623	  os << "  size_t numSerializedResults = compatibleResults;\n";
624	
625	  os << "\n";
626	}
