628	/// Generates C++ code within the 'write<OpName>' function to serialize the
629	/// result types of the given operation.
630	static void generateResultTypeSerialization(const Operator &op,
631	                                            raw_ostream &os) {
632	  // Check for unsupported AttrSizedResultSegments trait.
633	  if (op.getTrait("::mlir::OpTrait::AttrSizedResultSegments")) {
634	    os << "  op.emitError(\"operation '" << op.getOperationName()
635	       << "' has AttrSizedResultSegments, which is not supported by the "
636	          "bytecode writer.\");\n";
637	    os << "  return failure();\n";
638	  }
639	
640	  generateVersionAwareResultSerialization(op, os);
641	}
