643	/// Generates the complete C++ function 'write<OpName>'.
644	static void generateOpWriter(const Operator &op, raw_ostream &os) {
645	  std::string opName = op.getOperationName();
646	  os << "// Writer for Op: " << opName << "\n";
647	  generateFunctionSignature(op, os);
648	  generateResultTypeSerialization(op, os);
649	  generateFlagsFieldSerialization(op, os);
650	  generateAttributeSerialization(op, os);
651	  generateOperandSerialization(op, os);
652	  generateRegionSerialization(op, os);
653	  // Return the number of serialized results for valueIndexMap updates.
654	  os << "  return numSerializedResults;\n"
655	     << "}\n\n";
656	}
