682	/// Generates the TypeSwitch statement for dispatching to op-specific writers.
683	/// Returns FailureOr<size_t> where size_t is the number of serialized results.
684	static void generateDispatchSwitch(const RecordKeeper &records,
685	                                   raw_ostream &os) {
686	
687	  emitSourceFileHeader("Generated Bytecode Dispatch Switch", os);
688	  auto opDefs = records.getAllDerivedDefinitions("Op");
689	  os << "//"
690	        "===-------------------------------------------------------------------"
691	        "---===//\n"
692	     << "// Dispatch Switch\n"
693	     << "//"
694	        "===-------------------------------------------------------------------"
695	        "---===//\n\n";
696	
697	  os << "return TypeSwitch<Operation *, FailureOr<size_t>>(op)\n";
698	  for (const Record *opDef : opDefs) {
699	    Operator op(opDef);
700	    StringRef opClassName = op.getCppClassName();
701	    StringRef dialectNamespace = op.getDialect().getCppNamespace();
702	    std::string qualifiedClassName =
703	        dialectNamespace.str() + "::" + opClassName.str();
704	    os << "                   .Case<" << qualifiedClassName
705	       << ">([&](auto concreteOp) {\n"
706	       << "                     return write" << opClassName
707	       << "(concreteOp, writer, typeMgr, constMgr, strMgr, config);\n"
708	       << "                   })\n";
709	  }
710	  os << "                   .Default([&](Operation *) -> FailureOr<size_t> {\n"
711	     << "                     return op->emitError(\n"
712	     << "                         \"unhandled operation type in bytecode "
713	        "writer\");\n"
714	     << "                   });\n\n";
715	  os << "//"
716	        "===-------------------------------------------------------------------"
717	        "---===//\n"
718	     << "// End of generated dispatch switch.\n"
719	     << "//"
720	        "===-------------------------------------------------------------------"
721	        "---===//\n";
722	}
