743	/// Generate version constants based on actual opcode assignments
744	static void generateVersionConstants(const RecordKeeper &records,
745	                                     raw_ostream &os) {
746	  emitSourceFileHeader("Generated Version Constants", os);
747	
748	  auto opcodeRecords = records.getAllDerivedDefinitions("BytecodeOpcode");
749	
750	  // Track max opcode per version.
751	  llvm::DenseMap<std::pair<uint8_t, uint8_t>, uint32_t> versionToMaxOpcode;
752	
753	  for (const Record *record : opcodeRecords) {
754	    unsigned opcode = record->getValueAsInt("opcodeValue");
755	
756	    if (record->isSubClassOf("PublicOpcode")) {
757	      // Extract version from the operation definition.
758	      const Record *opRecord = record->getValueAsDef("operation");
759	
760	      // Parse version string from operation definition (e.g., "13.1" -> {13,
761	      // 1})
762	      StringRef versionStr = opRecord->getValueAsString("operationVersion");
763	      auto dotPos = versionStr.find('.');
764	      if (dotPos == StringRef::npos) {
765	        PrintFatalError(record->getLoc(),
766	                        "operation version must be in format 'major.minor'");
767	      }
768	
769	      unsigned majorVer, minorVer;
770	      if (versionStr.substr(0, dotPos).getAsInteger(10, majorVer) ||
771	          versionStr.substr(dotPos + 1).getAsInteger(10, minorVer)) {
772	        PrintFatalError(
773	            record->getLoc(),
774	            "invalid version format, expected 'major.minor' like '13.1'");
775	      }
776	
777	      // Store opcode for its minimum version.
778	      auto versionKey = std::make_pair(uint8_t(majorVer), uint8_t(minorVer));
779	      versionToMaxOpcode[versionKey] =
780	          std::max(versionToMaxOpcode[versionKey], opcode);
781	    }
782	  }
783	
784	  // Apply forward compatibility.
785	  auto versionRecords = records.getAllDerivedDefinitions("SupportedVersion");
786	
787	  std::vector<std::pair<uint8_t, uint8_t>> knownVersions;
788	  for (const Record *record : versionRecords) {
789	    unsigned major = record->getValueAsInt("majorVersion");
790	    unsigned minor = record->getValueAsInt("minorVersion");
791	    knownVersions.emplace_back(uint8_t(major), uint8_t(minor));
792	  }
793	
794	  std::sort(knownVersions.begin(), knownVersions.end());
795	
796	  uint32_t prevMaxOpcode = 0;
797	  for (auto version : knownVersions) {
798	    uint32_t &maxOpcode = versionToMaxOpcode[version];
799	    if (maxOpcode == 0)
800	      maxOpcode = prevMaxOpcode;
801	    prevMaxOpcode = maxOpcode;
802	  }
803	
804	  os << "namespace mlir {\nnamespace cuda_tile {\n\n";
805	
806	  // Generate version-to-max-opcode map accessor function
807	  os << "// Auto-generated version to max opcode mapping\n";
808	  os << "static const llvm::DenseMap<std::pair<uint8_t, uint8_t>, uint32_t> "
809	        "&getVersionToMaxOpcodeMap() {\n";
810	  os << "  static const llvm::DenseMap<std::pair<uint8_t, uint8_t>, uint32_t> "
811	        "map = []() {\n";
812	  os << "    llvm::DenseMap<std::pair<uint8_t, uint8_t>, uint32_t> m;\n";
813	  for (const auto &[versionPair, maxOpcode] : versionToMaxOpcode) {
814	    os << "    m[{" << static_cast<int>(versionPair.first) << ", "
815	       << static_cast<int>(versionPair.second) << "}] = 0x"
816	       << llvm::format("%X", maxOpcode) << ";\n";
817	  }
818	  os << "    return m;\n";
819	  os << "  }();\n";
820	  os << "  return map;\n";
821	  os << "}\n\n";
822	
823	  os << "} // namespace cuda_tile\n} // namespace mlir\n";
824	}
825	
826	/// Generate version validation function from SupportedVersion records.
827	static void generateVersionValidation(const RecordKeeper &records,
828	                                      raw_ostream &os) {
829	  emitSourceFileHeader("Generated Version Validation", os);
830	  auto versionRecords = records.getAllDerivedDefinitions("SupportedVersion");
831	  // Group versions by major version.
832	  std::map<uint8_t, std::vector<uint8_t>> versionMap;
833	
834	  for (const Record *record : versionRecords) {
835	    unsigned major = record->getValueAsInt("majorVersion");
836	    unsigned minor = record->getValueAsInt("minorVersion");
837	    versionMap[uint8_t(major)].push_back(uint8_t(minor));
838	  }
839	
840	  os << "// Auto-generated version validation from SupportedVersion records\n";
841	
842	  for (const auto &[major, minors] : versionMap) {
843	    bool isTestingVersion = (major == 250);
844	
845	    if (isTestingVersion) {
846	      os << "#ifdef TILE_IR_INCLUDE_TESTS\n";
847	      os << "  // Testing versions - only available when TILE_IR_INCLUDE_TESTS "
848	            "is defined.\n";
849	    }
850	
851	    os << "  if (verMajor == " << static_cast<int>(major) << ") {\n";
852	
853	    auto minIt = std::min_element(minors.begin(), minors.end());
854	    auto maxIt = std::max_element(minors.begin(), minors.end());
855	
856	    if (*minIt == *maxIt)
857	      os << "    if (verMinor == " << static_cast<int>(*minIt) << ")\n";
858	    else if (*minIt == 0)
859	      os << "    if (verMinor <= " << static_cast<int>(*maxIt) << ")\n";
860	    else
861	      os << "    if (verMinor >= " << static_cast<int>(*minIt)
862	         << " && verMinor <= " << static_cast<int>(*maxIt) << ")\n";
863	
864	    os << "      return BytecodeVersion(verMajor, verMinor, verTag);\n";
865	    os << "  }\n";
866	
867	    if (isTestingVersion)
868	      os << "#endif // TILE_IR_INCLUDE_TESTS\n";
869	  }
870	
871	  os << "  return std::nullopt;\n";
872	}
