874	/// Generate getSupportedVersions() function from SupportedVersion records.
875	static void generateSupportedVersionsList(const RecordKeeper &records,
876	                                          raw_ostream &os) {
877	  emitSourceFileHeader("Generated Supported Versions List", os);
878	  auto versionRecords = records.getAllDerivedDefinitions("SupportedVersion");
879	
880	  // Collect and sort all versions.
881	  std::vector<std::pair<uint8_t, uint8_t>> versions;
882	  for (const Record *record : versionRecords) {
883	    unsigned major = record->getValueAsInt("majorVersion");
884	    unsigned minor = record->getValueAsInt("minorVersion");
885	    versions.emplace_back(uint8_t(major), uint8_t(minor));
886	  }
887	  llvm::sort(versions);
888	
889	  std::string versionList;
890	  llvm::raw_string_ostream vos(versionList);
891	  llvm::interleaveComma(versions, vos, [&](const auto &v) {
892	    vos << llvm::formatv("*BytecodeVersion::fromVersion({0}, {1}, 0)",
893	                         static_cast<int>(v.first), static_cast<int>(v.second));
894	  });
895	
896	  os << llvm::formatv(R"(// Auto-generated list of supported bytecode versions.
897	llvm::SmallVector<BytecodeVersion> mlir::cuda_tile::getSupportedVersions() {{
898	  return {{{0}};
899	}
900	)",
901	                      versionList);
902	}
