212	
213	  // Always declare flags variable for use in conditional logic below.
214	  if (totalOptionalFields > 0) {
215	    os << "  // Read flags field for optional attributes/operands.\n"
216	       << "  uint64_t flags = 0;\n";
217	
218	    // Forward Compatibility: Only generate version check if the first optional
219	    // field was added AFTER the operation's baseline version. This allows newer
220	    // readers (e.g., 13.2) to read older bytecode (e.g., 13.1) that was written
221	    // before optional fields existed. If optional fields existed from the
222	    // operation's baseline, flags field is always present and no check needed.
223	    std::string opVersion = extractVersionFromOperation(op);
224	    std::string minOptionalVersionStr =
225	        minOptionalVersion
226	            ? (minOptionalVersion->first + "." + minOptionalVersion->second)
227	            : "";
228	    bool needsVersionCheck =
229	        minOptionalVersion && (minOptionalVersionStr != opVersion);
230	
231	    if (needsVersionCheck) {
232	      auto [majorStr, minorStr] = *minOptionalVersion;
233	      os << llvm::formatv(
234	          R"(  // Only read flags if bytecode version supports it (>= {0}.{1})
235	  auto requiredVersionForFlags = BytecodeVersion::fromVersion({0}, {1}, 0);
236	  assert(requiredVersionForFlags && "TableGen should guarantee valid versions");
237	  if (bytecodeVersion >= *requiredVersionForFlags) {{
238	    if (failed(reader.readVarInt(flags)))
239	      return reader.emitError() << "failed to read flags field";
240	  }
241	  // Else: flags stays 0 (no optional fields in older bytecode versions)
242	
243	)",
244	          majorStr, minorStr);
245	    } else {
246	      // Flags field always exists for this operation.
247	      os << "  if (failed(reader.readVarInt(flags)))\n"
248	         << "    return reader.emitError() << \"failed to read flags "
249	            "field\";\n\n";
250	    }
