333	
334	    os << "  "
335	          "attributes.emplace_back(innerBuilder.getStringAttr(\"operand_"
336	          "segment_sizes\"), "
337	          "mlir::DenseI32ArrayAttr::get(&context, readSegmentSizes));\n";
338	
339	  } else {
340	    os << "  // Standard operand deserialization for ops without "
341	          "AttrSizedOperandSegments.\n";
342	    bool opHasOptionalOperands =
343	        llvm::any_of(opDef.getOperands(),
344	                     [](const auto &operand) { return operand.isOptional(); });
345	    bool opHasVariadicOperands =
346	        llvm::any_of(opDef.getOperands(),
347	                     [](const auto &operand) { return operand.isVariadic(); });
348	    bool readSizeFromStream = opHasVariadicOperands || opHasOptionalOperands;
349	    os << llvm::formatv(operandDeserializationTemplate,
350	                        readSizeFromStream
351	                            ? "std::nullopt"
352	                            : std::to_string(opDef.getNumOperands()));
353	  }
354	}
355	
356	/// Generates C++ code within the 'parse<OpName>' function to deserialize the
357	/// attributes of the given operation by calling the parseOpAttribute helper.
358	static void
359	generateAttributeDeserialization(const Operator &op, raw_ostream &os,
360	                                 const StringMap<size_t> &bitAssignments) {
361	  os << R"(
362	  // --- Deserialize Attributes ---
363	  SmallVector<NamedAttribute> attributes;
364	  )";
365	
366	  for (const NamedAttribute &namedAttr : op.getAttributes()) {
367	    std::string attrName = namedAttr.name.str();
368	    std::string varName = "parsed_" + attrName;
369	    StringRef baseCppTypeStr = namedAttr.attr.getStorageType();
370	    bool isOptional = namedAttr.attr.isOptional();
371	    bool isUnitAttr = baseCppTypeStr.contains("UnitAttr");
372	
373	    // Declare the attribute variable
374	    os << llvm::formatv(R"(  {0} {1};)", baseCppTypeStr, varName) << "\n";
375	
376	    // Determine expectedType for parseOpAttribute
377	    bool isElements = baseCppTypeStr.contains("ElementsAttr");
378	    std::string expectedTypeArg = "nullptr";
379	    std::string expectedTypeDeclaration;
380	
381	    if (isElements && op.getNumResults() > 0) {
382	      expectedTypeArg = "resultTypes.empty() ? nullptr : resultTypes[0]";
383	    } else if (baseCppTypeStr == "::mlir::IntegerAttr") {
384	      StringRef attrDefName = namedAttr.attr.getAttrDefName();
385	      static const llvm::StringMap<unsigned> attrWidthMap = {
386	          {"I1Attr", 1},   {"I8Attr", 8},   {"I16Attr", 16},
387	          {"I32Attr", 32}, {"I64Attr", 64},
388	      };
389	      auto it = attrWidthMap.find(attrDefName);
390	      if (it != attrWidthMap.end()) {
391	        unsigned width = it->second;
392	        std::string typeVarName = varName + "_expectedType";
393	        expectedTypeDeclaration =
394	            formatv("  Type {0} = IntegerType::get(&context, {1});\n",
395	                    typeVarName, width);
396	        expectedTypeArg = typeVarName;
397	      } else {
398	        os << formatv(
399	            R"(  return reader.emitError() << "could not determine width for inline IntegerAttr '{0}' with definition '{1}'";)"
400	            "\n",
401	            attrName, attrDefName);
402	      }
403	    }
404	    // Emit the expected type declaration if needed.
405	    os << expectedTypeDeclaration;
406	
407	      os << "  // Public operations: use version checking\n";
408	      // For public operations, add version checking.
409	      auto [majorStr, minorStr] = extractVersionFromAttribute(namedAttr, op);
410	      auto defaultValue = extractDefaultValue(namedAttr);
411	      std::string version = majorStr + "." + minorStr;
412	
413	      os << llvm::formatv(R"(
414	  auto requiredVersionFor_{0} = BytecodeVersion::fromVersion({1}, {2}, 0);
415	  assert(requiredVersionFor_{0} && "TableGen should guarantee valid versions");
416	  if (bytecodeVersion >= *requiredVersionFor_{0}) {{
417	)",
418	                          attrName, majorStr, minorStr);
419	
420	      // Generate parsing logic within version check.
421	      int bitPos =
422	          isOptional ? static_cast<int>(bitAssignments.lookup(attrName)) : -1;
423	      generateAttributeParsingLogic(os, varName, expectedTypeArg, attrName,
424	                                    baseCppTypeStr, isOptional, isUnitAttr,
425	                                    bitPos);
426	
427	      os << "  } else {\n"
428	         << "    // For older bytecode versions, use default value\n";
429	      if (defaultValue.has_value()) {
430	        // Handle different attribute types with their specific construction
431	        // patterns
432	        if (baseCppTypeStr.contains("UnitAttr")) {
433	          // UnitAttr with false default means don't create the attribute
434	          // (nullptr).
435	          if (*defaultValue == "false")
436	            os << "    " << varName << " = nullptr;\n";
437	          else
438	            os << "    " << varName << " = ::mlir::UnitAttr::get(&context);\n";
439	        } else if (baseCppTypeStr.contains("IntegerAttr")) {
440	          // IntegerAttr needs a type.
441	          os << "    " << varName << " = ::mlir::IntegerAttr::get("
442	             << expectedTypeArg << ", " << *defaultValue << ");\n";
443	        } else if (baseCppTypeStr.contains("BoolAttr")) {
444	          // BoolAttr construction.
445	          os << "    " << varName << " = ::mlir::BoolAttr::get(&context, "
446	             << *defaultValue << ");\n";
447	        } else if (baseCppTypeStr.contains("cuda_tile::")) {
448	          // Custom cuda_tile attributes follow the standard pattern.
449	          os << "    " << varName << " = " << baseCppTypeStr
450	             << "::get(&context, " << *defaultValue << ");\n";
451	        } else {
452	          PrintFatalError("Versioned attribute type '" + baseCppTypeStr.str() +
453	                          "' is not supported. Please add explicit handling in "
454	                          "BytecodeReaderGen.cpp for operation '" +
455	                          op.getOperationName() + "'");
456	        }
457	      } else {
458	        // No default value available.
459	        std::string opVersion = extractVersionFromOperation(op);
460	        if (version != opVersion) {
461	          // For attributes introduced after the operation itself
462	          if (namedAttr.attr.isOptional()) {
463	            // Optional attributes should be nullptr (missing) for older
464	            // versions
465	            os << "    " << varName << " = nullptr;\n";
466	          } else {
467	            // Required attributes introduced after the operation must have
468	            // default value
469	            PrintFatalError(
470	                "Versioned attribute '" + namedAttr.name + "' in operation '" +
471	                op.getOperationName() + "' (since " + version +
472	                ") was introduced after the operation itself (since " +
473	                opVersion +
474	                ") and must have a default value for backward compatibility");
475	          }
476	        }
477	        // Note: Attributes introduced with the operation itself don't need
478	        // defaults.
479	      }
480	      os << "  }\n";
481	    // Generate attribute addition to the attributes vector.
482	    os << formatv(R"(  if ({0}) {{
483	    attributes.emplace_back(innerBuilder.getStringAttr("{1}"), {2});})",
484	                  varName, attrName, varName);
485	  }
486	  os << "\n";
487	}
488	
489	/// Generate result deserialization without version checking.
490	static void generateSimpleResultDeserialization(const Operator &op,
491	                                                raw_ostream &os) {
492	  StringRef opClassName = op.getCppClassName();
493	  os << "  // Deserialize results directly.\n";
494	
495	  std::string numResultsStr;
496	  if (op.isVariadic()) {
497	    os << "  uint64_t numActualResults;\n"
498	       << "  if (failed(reader.readVarInt(numActualResults,\n"
499	       << "             std::numeric_limits<uint32_t>::max() - 1)))\n"
500	       << "    return reader.emitError() << \"failed to read number of result "
501	          "types for "
502	       << opClassName << "\";\n";
503	    numResultsStr = "numActualResults";
504	  } else {
505	    numResultsStr = std::to_string(op.getNumResults());
506	  }
507	  os << "  // --- Read Result Types ---\n";
508	  os << llvm::formatv(resultTypeDeserializationTemplate, numResultsStr,
509	                      opClassName);
510	  // For simple deserialization, all results were serialized.
511	  os << "  std::optional<size_t> numResultsForValueIndex = std::nullopt;\n";
512	}
513	
514	/// Generate version-aware result deserialization.
515	static void generateVersionAwareResultDeserialization(const Operator &op,
516	                                                      raw_ostream &os) {
517	  StringRef opClassName = op.getCppClassName();
518	  os << "  // Public operations: version checking for results.\n";
519	
520	  std::string opVersion = extractVersionFromOperation(op);
521	
522	  // Single analysis pass - collect version info for all results.
523	  SmallVector<ResultVersionInfo> versionInfos;
524	  bool hasVersionedResults = false;
525	
526	  for (int i = 0; i < op.getNumResults(); ++i) {
527	    ResultVersionInfo info(i, op.getResult(i), op, opVersion);
528	    if (info.requiresVersionCheck)
529	      hasVersionedResults = true;
530	    versionInfos.push_back(std::move(info));
531	  }
532	
533	  if (!hasVersionedResults) {
534	    // All results from original operation - use simple deserialization.
535	    generateSimpleResultDeserialization(op, os);
536	    return;
537	  }
538	
539	  os << llvm::formatv(R"(
540	  // --- Read Result Types (Version-Aware) ---
541	  SmallVector<Type> resultTypes;
542	)");
543	
544	  if (op.isVariadic()) {
545	    os << llvm::formatv(R"(
546	  uint64_t numSerializedResults;
547	  if (failed(reader.readVarInt(numSerializedResults,
548	             std::numeric_limits<uint32_t>::max() - 1)))
549	    return reader.emitError() << "failed to read number of result types for {0}";
550	)",
551	                        opClassName);
552	  }
553	
554	  os << llvm::formatv(R"(
555	  uint64_t expectedResults = 0;
556	  uint64_t resultIndex = 0;
557	)");
558	
559	  for (int i = 0; i < op.getNumResults(); ++i) {
560	    const auto &info = versionInfos[i];
561	
562	    if (!info.requiresVersionCheck) {
563	      // Original result always compatible.
564	      os << llvm::formatv(R"(
565	  ++expectedResults;
566	  Type resultType = types.readAndGetType(reader);
567	  if (!resultType)
568	    return reader.emitError() << "failed to get result type " << resultIndex << " for {0}";
569	  resultTypes.push_back(resultType);
570	  ++resultIndex;
571	)",
572	                          opClassName);
573	    } else {
574	      // Add default result type based on actual type constraint.
575	      const auto &result = op.getResult(i);
576	      const auto &constraint = result.constraint;
577	
578	      std::string defaultTypeCode;
579	      std::optional<StringRef> builderCall = constraint.getBuilderCall();
580	      if (builderCall.has_value()) {
581	        FmtContext fctx;
582	        fctx.withBuilder("innerBuilder");
583	        fctx.addSubst("_ctxt", "&context");
584	        defaultTypeCode = "    resultTypes.push_back(" +
585	                          tgfmt(*builderCall, &fctx).str() + ");\n";
586	      } else {
587	        PrintFatalError("Result '" + result.name.str() + "' in operation '" +
588	                        op.getOperationName() +
589	                        "' has non-buildable type constraint '" +
590	                        constraint.getDefName().str() +
591	                        "'. Results introduced after operation version must "
592	                        "have buildable types.");
593	      }
594	
595	      os << llvm::formatv(
596	          R"(
597	  auto requiredVersionFor_result_{0} = BytecodeVersion::fromVersion({1}, {2}, 0);
598	  assert(requiredVersionFor_result_{0} && "TableGen should guarantee valid versions");
599	  if (bytecodeVersion >= *requiredVersionFor_result_{0}) {{
600	    ++expectedResults;
601	    Type resultType = types.readAndGetType(reader);
602	    if (!resultType)
603	      return reader.emitError() << "failed to get result type " << resultIndex << " for {3}";
604	    resultTypes.push_back(resultType);
605	    ++resultIndex;
606	  } else {{
607	    // Result introduced in newer version.
608	{4}  }
609	)",
610	          info.name, info.majorStr, info.minorStr, opClassName,
611	          defaultTypeCode);
612	    }
613	  }
614	
615	  if (op.isVariadic()) {
616	    os << llvm::formatv(R"(
617	  if (numSerializedResults != expectedResults)
618	    return reader.emitError() << "result count mismatch for {0}: expected " << expectedResults 
619	                              << " compatible results but got " << numSerializedResults;
620	)",
621	                        opClassName);
622	  }
623	
624	  // For version-aware deserialization, only add serialized results to
625	  // valueIndexList. Results introduced in newer versions (with default types)
626	  // should not be added to valueIndexList to preserve SSA value numbering.
627	  os << "  std::optional<size_t> numResultsForValueIndex = expectedResults;\n";
628	}
629	
630	/// Generates C++ code to deserialize the result types of the operation.
631	static void generateResultTypeDeserialization(const Operator &op,
632	                                              raw_ostream &os) {
633	  generateVersionAwareResultDeserialization(op, os);
634	}
635	
636	/// Generates C++ code within the 'parse<OpName>' function to deserialize the
637	/// regions of the given operation, if it has any.
638	static void generateRegionDeserialization(const Operator &op, raw_ostream &os) {
639	  os << R"(  // --- Read Regions ---
640	  SmallVector<std::unique_ptr<Region>> parsedRegions;
641	)";
642	  if (op.getNumRegions() != 0)
643	    os << llvm::formatv(regionDeserializationTemplate, op.getOperationName(),
644	                        op.getNumRegions());
645	}
646	
647	/// Generates C++ code within the 'parse<OpName>' function to deserialize the
648	/// operation.
649	static void generateOperationDeserialization(const Operator &op,
650	                                             raw_ostream &os) {
651	  std::string opName = op.getOperationName();
652	  os << llvm::formatv(operationDeserializationTemplate, opName,
653	                      "numResultsForValueIndex");
654	}
655	
656	/// Generates the complete C++ function 'parse<OpName>'.
657	static void generateOpReader(const Operator &op, raw_ostream &os) {
658	  std::string opName = op.getOperationName();
659	  auto [bitAssignments, minOptionalVersion] =
660	      getVersionOrderedBitAssignments(op);
661	  os << "// Reader for Op: " << opName << "\n";
662	
663	  generateFunctionSignature(op, os);
664	  generateResultTypeDeserialization(op, os);
665	  generateFlagsFieldDeserialization(op, os, bitAssignments, minOptionalVersion);
666	  generateAttributeDeserialization(op, os, bitAssignments);
667	  generateOperandDeserialization(op, os, bitAssignments);
668	  generateRegionDeserialization(op, os);
669	  generateOperationDeserialization(op, os);
670	  os << "  return success();\n"
671	     << "}\n\n";
672	}
673	
674	/// Generates the implementations of the individual op reader functions.
675	static void generateOpReaderImplementations(const RecordKeeper &records,
676	                                            raw_ostream &os) {
677	
678	  emitSourceFileHeader("Generated Bytecode Reader Functions", os);
679	  auto opDefs = records.getAllDerivedDefinitions("Op");
680	  for (const Record *opDef : opDefs)
681	    generateOpReader(Operator(opDef), os);
682	  os << R"(//===----------------------------------------------------------------------===//
683	// End of generated functions.
684	//===----------------------------------------------------------------------===//
685	)";
686	}
687	
688	/// Generates the C++ switch statement to dispatch based on opcode.
689	static void generateOpReaderDispatch(const RecordKeeper &records,
690	                                     raw_ostream &os) {
691	  emitSourceFileHeader("Generated Bytecode Opcode Dispatcher", os);
692	  auto opDefs = records.getAllDerivedDefinitions("Op");
693	  os << R"(switch (static_cast<Opcode>(opcode)) {)";
694	  for (const Record *opDef : opDefs) {
695	    Operator op(opDef);
696	    StringRef opClassName = op.getCppClassName();
697	    os << llvm::formatv(dispatchCaseTemplate, opClassName);
698	  }
699	  os << R"(  default:
700	    return reader.emitError() << "unknown or unimplemented opcode: " << static_cast<int>(opcode);})";
701	  os << R"(//===-------------------------------------------------------------------//
702	// End of generated dispatcher.
703	//===-------------------------------------------------------------------//
704	)";
705	}
706	
707	/// The main entry point for the TableGen backend.
708	static bool generateBytecodeReader(const RecordKeeper &records,
709	                                   raw_ostream &os) {
710	  os << "//===-- Begin Reader Implementations --===//\n"
711	     << "#ifdef GEN_OP_READERS\n\n";
712	  generateOpReaderImplementations(records, os);
713	  os << "#undef GEN_OP_READERS\n"
714	     << "#endif // GEN_OP_READERS\n"
715	     << "//===-- End Reader Implementations --===//\n\n";
716	
717	  os << "//===-- Begin Opcode Dispatcher --===//\n"
718	     << "#ifdef GEN_OP_READER_DISPATCH\n\n";
719	  generateOpReaderDispatch(records, os);
720	  os << "#undef GEN_OP_READER_DISPATCH\n"
721	     << "#endif // GEN_OP_READER_DISPATCH\n"
722	     << "//===-- End Opcode Dispatcher --===//\n\n";
723	
724	  return false;
725	}
726	
727	/// Generate type reader bytecode functions.
728	static bool generateTypeReaderBytecode(const RecordKeeper &records,
729	                                       raw_ostream &os) {
730	  // Phase 1: Analysis - parse TableGen records.
731	  auto structureOrError = analyzeBytecodeTypes(records);
732	  if (failed(structureOrError)) {
733	    PrintFatalError("Failed to analyze bytecode types");
734	    return true;
735	  }
736	  const auto &structure = *structureOrError;
737	
738	  // Phase 2: Generation - use analyzed structure for all outputs.
739	  os << "//===-- Begin Type Reader Implementations --===//\n";
740	  os << "#ifdef GEN_TYPE_READERS\n\n";
741	  generateTypeDeserializers(structure, os);
742	  os << "#undef GEN_TYPE_READERS\n";
743	  os << "#endif // GEN_TYPE_READERS\n";
744	  os << "//===-- End Type Reader Implementations --===//\n\n";
745	
746	  os << "//===-- Begin Type Reader Dispatch --===//\n";
747	  os << "#ifdef GEN_TYPE_READER_DISPATCH\n\n";
748	  generateDeserializerDispatch(structure, os);
749	  os << "#undef GEN_TYPE_READER_DISPATCH\n";
750	  os << "#endif // GEN_TYPE_READER_DISPATCH\n";
751	  os << "//===-- End Type Reader Dispatch --===//\n";
752	
753	  return false;
754	}
755	
756	/// Register the generator.
757	static mlir::GenRegistration genCudaTileBytecodeReader(
758	    "gen-cuda-tile-bytecode-reader",
759	    "Generate cuda_tile bytecode reader implementations.",
760	    [](const RecordKeeper &records, raw_ostream &os) {
761	      return generateBytecodeReader(records, os);
762	    });
763	
764	static mlir::GenRegistration genCudaTileTypeBytecodeReader(
765	    "gen-cuda-tile-type-bytecode-reader",
766	    "Generate cuda_tile type bytecode reader implementations.",
767	    [](const RecordKeeper &records, raw_ostream &os) {
768	      return generateTypeReaderBytecode(records, os);
769	    });
