150	/// Get parameters in serialization order.
151	static SmallVector<BytecodeTypeParameter, 4>
152	getSerializationOrder(const CudaTileType &type) {
153	  if (type.needsReverseOrder)
154	    return llvm::to_vector<4>(llvm::reverse(type.parameters));
155	  return type.parameters;
