158	/// Check if version string is >= 13.3 (unified bitfield format).
159	/// Types introduced at 13.3+ always use unified format.
160	static bool isUnifiedBitfieldVersion(StringRef version) {
161	  auto [majorStr, minorStr] = parseVersion(version);
162	  int major = std::stoi(majorStr);
163	  int minor = std::stoi(minorStr);
164	  return (major > 13) || (major == 13 && minor >= 3);
165	}
