175	/// Generate version check with proper indentation.
176	static std::string
177	generateVersionCheck(unsigned indent, StringRef version, StringRef typeName,
178	                     StringRef versionVar = "config.bytecodeVersion",
179	                     StringRef contextExpr = "type.getContext()",
180	                     StringRef errorSuffix = "targeting ") {
181	  auto [majorStr, minorStr] = parseVersion(version);
182	  std::string indentStr(indent, ' ');
183	  return formatv("{0}if ({1} < *BytecodeVersion::fromVersion({2}, {3}, 0))\n"
184	                 "{0}  return ::emitError(UnknownLoc::get({4}))\n"
185	                 "{0}         << \"type '{5}' requires bytecode version {6}+, "
186	                 "{7}\" << {1}.toString();\n",
187	                 indentStr, versionVar, majorStr, minorStr, contextExpr,
188	                 typeName, version, errorSuffix)
189	      .str();
190	}
