211	
212	static void generateParameterSerialization(const BytecodeTypeParameter &param,
213	                                           raw_ostream &os,
214	                                           StringRef indent = "",
215	                                           StringRef runtimeFlag = "") {
216	  std::string getterCall = "type." + param.accessorName + "()";
217	  mlir::raw_indented_ostream ios(os);
218	
219	  switch (param.kind) {
220	  case BytecodeTypeParameter::Kind::Int64Array:
221	  case BytecodeTypeParameter::Kind::Int32Array:
222	    ios.printReindented(formatv(serializeArrayTemplate, getterCall).str(),
223	                        indent);
224	    break;
225	  case BytecodeTypeParameter::Kind::UInt32Scalar:
226	    ios.printReindented(
227	        formatv(serializeUInt32ScalarTemplate, getterCall).str(), indent);
228	    break;
229	  case BytecodeTypeParameter::Kind::DenseI32Array:
230	    ios.printReindented(
231	        formatv(serializeDenseI32ArrayTemplate, getterCall).str(), indent);
232	    break;
233	  case BytecodeTypeParameter::Kind::GenericType:
234	  case BytecodeTypeParameter::Kind::SpecificType:
235	    ios.printReindented(formatv(serializeTypeTemplate, getterCall).str(),
236	                        indent);
237	    break;
238	  case BytecodeTypeParameter::Kind::OptionalEnum:
239	    ios.printReindented(formatv(serializeOptionalEnumTemplate, getterCall,
240	                                param.enumTypeName, runtimeFlag)
241	                            .str(),
242	                        indent);
243	    break;
244	  default:
245	    llvm::PrintFatalError("Unsupported parameter kind in code generation");
246	  }
247	}
