344	//===----------------------------------------------------------------------===//
345	// C++ Generator - Optional Parameter Flags (Writer).
346	//===----------------------------------------------------------------------===//
347	//
348	// Optional Parameter Handling:
349	//
350	// Types can have optional parameters (OptionalParameter<T>) that may be null.
351	// These use a bitfield-based encoding for efficient serialization.
352	//
353	// Format Evolution:
354	//   Version <13.3 (Legacy):
355	//     - OptionalEnum: Uses inline flag byte per parameter
356	//     - Optional Type: Not supported as it was added in later versions.
357	//
358	//   Version ≥13.3 (Unified Bitfield):
359	//     - ALL optional params (Type, Enum, etc.): Single unified bitfield
360	//     - No inline flags - bitfield indicates presence
361	//
362	// Bitfield Layout:
363	//   - Bit 0: First optional param (in serialization order)
364	//   - Bit N: Nth optional param
365	//   - Bit set (1) = present, Bit clear (0) = null/absent
366	//
367	// Version Checking:
368	//   Flags written if:
369	//     1. config.bytecodeVersion >= firstOptionalParamVersion (type supports it)
370	//     2. config.bytecodeVersion >= 13.3 (unified format exists)
371	//   This allows targeting older versions for backward compatibility.
372	//
373	//===----------------------------------------------------------------------===//
374	
375	/// Generates flags field serialization for optional type parameters.
376	static void generateOptionalParamFlags(const CudaTileType &type,
377	                                       raw_ostream &os) {
378	  if (!type.hasOptionalTypeParams)
379	    return;
380	
381	  if (type.skipVersionCheck) {
382	    os << R"(
383	  bool useUnifiedBitfield = true;
384	)";
385	  } else {
386	    os << R"(
387	  bool useUnifiedBitfield = config.bytecodeVersion >= BytecodeVersion::kUnifiedBitfieldVersion;
388	)";
389	  }
390	
391	  os << R"(  uint64_t optionalFlags = 0;
392	)";
393	
394	  // Build flags for all optional params.
395	  unsigned bitIndex = 0;
396	  for (const auto &param : getSerializationOrder(type)) {
397	    if (param.usesOptionalTypeFlags) {
398	      os << formatv(R"(  if (type.{0}()) optionalFlags |= (1ULL << {1});
399	)",
400	                    param.accessorName, bitIndex++);
401	    }
402	  }
403	
404	  // Write flags.
405	  if (type.skipVersionCheck) {
406	    os << "  writer.writeVarInt(optionalFlags);\n";
407	  } else {
408	    std::string minOptionalVersionStr = type.firstOptionalTypeParamVersion;
409	    bool needsVersionCheck = !minOptionalVersionStr.empty() &&
410	                             (minOptionalVersionStr != type.sinceVersion);
411	    // Types >= 13.3 don't need runtime >= 13.3 check.
412	    bool typeIsUnified = isUnifiedBitfieldVersion(type.sinceVersion);
413	
414	    if (needsVersionCheck) {
415	      auto [majorStr, minorStr] = parseVersion(minOptionalVersionStr);
416	      if (typeIsUnified) {
417	        // Type >= 13.3: only check >= firstOptionalVersion.
418	        os << formatv(R"(  
419	  if (config.bytecodeVersion >= *BytecodeVersion::fromVersion({0}, {1}, 0))
420	    writer.writeVarInt(optionalFlags);
421	)",
422	                      majorStr, minorStr);
423	      } else {
424	        // Type < 13.3: check both versions.
425	        os << formatv(R"(  
426	  if (config.bytecodeVersion >= *BytecodeVersion::fromVersion({0}, {1}, 0) &&
427	      config.bytecodeVersion >= BytecodeVersion::kUnifiedBitfieldVersion)
428	    writer.writeVarInt(optionalFlags);
429	)",
430	                      majorStr, minorStr);
431	      }
432	    } else {
433	      if (typeIsUnified) {
434	        // Type >= 13.3: no check needed.
435	        os << "  writer.writeVarInt(optionalFlags);\n";
436	      } else {
437	        // Type < 13.3: check >= 13.3.
438	        os << R"(  
439	  if (config.bytecodeVersion >= BytecodeVersion::kUnifiedBitfieldVersion)
440	    writer.writeVarInt(optionalFlags);
441	)";
442	      }
443	    }
444	  }
445	}
