447	//===----------------------------------------------------------------------===//
448	// C++ Generator - Type Serializers.
449	//===----------------------------------------------------------------------===//
450	//
451	// Generates serialization function for each CudaTile type.
452	// For types with optional parameters, uses unified bitfield (13.3+) or
453	// legacy inline flags (<13.3). See "Optional Parameter Flags" section above.
454	//
455	//===----------------------------------------------------------------------===//
456	
457	static void generateCudaTileTypeSerializer(const CudaTileType &type,
458	                                           raw_ostream &os) {
459	  // Function signature
460	  os << formatv(cudaTileSerializerSignatureTemplate, type.typeName,
461	                type.qualifiedTypeName);
462	
463	  if (!type.skipVersionCheck)
464	    os << generateVersionCheck(2, type.sinceVersion, type.typeName);
465	
466	  // Write type tag.
467	  os << "  writer.writeVarInt(Bytecode::TypeTag::" << type.typeName << ");\n";
468	
469	  // Declare format flag and write flags only if type has optional params.
470	  generateOptionalParamFlags(type, os);
471	
472	  // Serialize parameters conditionally based on target bytecode version.
473	  for (const auto &param : getSerializationOrder(type)) {
474	    bool isEvolved =
475	        !type.skipVersionCheck && param.sinceVersion != type.sinceVersion;
476	
477	    // Original parameters - always serialize.
478	    if (!isEvolved) {
479	      generateParameterSerialization(param, os, "  ", "useUnifiedBitfield");
480	      continue;
481	    }
482	
483	    // Evolved parameters - version-guarded with validation.
484	    auto [majorStr, minorStr] = parseVersion(param.sinceVersion);
485	    std::string getterCall = "type." + param.accessorName + "()";
486	    std::string defaultValue =
487	        replaceTableGenPlaceholders(param.defaultValue, "type.getContext()");
488	
489	    // Validate: null check for optional, equality for non-optional.
490	    std::string validationCheck =
491	        param.usesOptionalTypeFlags
492	            ? formatv("if ({0})", getterCall).str()
493	            : formatv("if ({0} != {1})", getterCall, defaultValue).str();
494	
495	    os << formatv(R"(
496	  if (config.bytecodeVersion >= *BytecodeVersion::fromVersion({0}, {1}, 0)) {{
497	)",
498	                  majorStr, minorStr);
499	
500	    // Serialize parameter.
501	    if (param.usesOptionalTypeFlags) {
502	      os << formatv("    if ({0}) {{\n", getterCall);
503	      generateParameterSerialization(param, os, "      ", "useUnifiedBitfield");
504	      os << "    }\n";
505	    } else {
506	      generateParameterSerialization(param, os, "    ", "useUnifiedBitfield");
507	    }
508	
509	    os << formatv(R"(  } else {{
510	      // Validate: parameter must be null/equal default when targeting older version.
511	      {0}
512	      return emitError(UnknownLoc::get(type.getContext()),
513	                   "parameter '{1}' requires bytecode version {2}+, but targeting ") << config.bytecodeVersion.toString();
514	  }
515	)",
516	                  validationCheck, param.name, param.sinceVersion);
517	  }
518	
519	  os << "  return success();\n}\n\n";
520	}
