585	//===----------------------------------------------------------------------===//
586	// C++ Generator - Optional Parameter Flags (Reader).
587	//===----------------------------------------------------------------------===//
588	//
589	// Reads the optional parameter bitfield written by the writer.
590	// See "Optional Parameter Flags (Writer)" section above for format details.
591	//
592	// Reading Strategy:
593	//   - Determine format from fileVersion (≥13.3 = unified, <13.3 = legacy)
594	//   - Read bitfield if: fileVersion >= firstOptionalParamVersion && unified
595	//   - For legacy format: OptionalEnum uses inline flags (read by templates)
596	//
597	//===----------------------------------------------------------------------===//
598	
599	/// Generates flags field deserialization for optional type parameters.
600	static void generateOptionalParamFlagsReader(const CudaTileType &type,
601	                                             raw_ostream &os) {
602	  if (!type.hasOptionalTypeParams)
603	    return;
604	
605	  if (type.skipVersionCheck) {
606	    os << R"(
607	  bool useUnifiedBitfield = true;
608	  uint64_t optionalFlags = 0;
609	  if (failed(reader.readVarInt(optionalFlags)))
610	    return reader.emitError() << "failed to read optional parameter flags";
611	)";
612	  } else {
613	    // Types >= 13.3 don't need runtime >= 13.3 check.
614	    bool typeIsUnified = isUnifiedBitfieldVersion(type.sinceVersion);
615	    std::string minOptionalVersionStr = type.firstOptionalTypeParamVersion;
616	    auto [majorStr, minorStr] = parseVersion(minOptionalVersionStr);
617	
618	    if (typeIsUnified) {
619	      // Type >= 13.3: useUnifiedBitfield is always true.
620	      os << formatv(R"(
621	  bool useUnifiedBitfield = true;
622	  uint64_t optionalFlags = 0;
623	  if (fileVersion >= *BytecodeVersion::fromVersion({0}, {1}, 0)) {{
624	    if (failed(reader.readVarInt(optionalFlags)))
625	      return reader.emitError() << "failed to read optional parameter flags";
626	  }
627	)",
628	                    majorStr, minorStr);
629	    } else {
630	      // Type < 13.3: need runtime check for unified format.
631	      os << R"(
632	  bool useUnifiedBitfield = fileVersion >= BytecodeVersion::kUnifiedBitfieldVersion;
633	)";
634	      os << formatv(R"(
635	  uint64_t optionalFlags = 0;
636	  if (fileVersion >= *BytecodeVersion::fromVersion({0}, {1}, 0) && useUnifiedBitfield) {{
637	    if (failed(reader.readVarInt(optionalFlags)))
638	      return reader.emitError() << "failed to read optional parameter flags";
639	  }
640	)",
641	                    majorStr, minorStr);
642	    }
643	  }
644	}
645	
646	//===----------------------------------------------------------------------===//
647	// C++ Generator - Type Deserializers.
648	//===----------------------------------------------------------------------===//
649	//
650	// Generates deserialization function for each CudaTile type.
651	// Reads optional parameter bitfield (13.3+) or inline flags (<13.3).
652	// See "Optional Parameter Flags" sections above for format details.
653	//
654	//===----------------------------------------------------------------------===//
655	
656	static void generateCudaTileTypeDeserializer(const CudaTileType &type,
657	                                             raw_ostream &os) {
658	  os << formatv(R"(// Reader for Type: {0}
659	LogicalResult parse{0}(EncodingReader &reader, Type &result) {{
660	)",
661	                type.typeName);
662	
663	  // Version check for the type itself.
664	  if (!type.skipVersionCheck)
665	    os << generateVersionCheck(2, type.sinceVersion, type.typeName,
666	                               "fileVersion", "&context", "file version is ");
667	
668	  // Declare format flag and read flags only if type has optional params.
669	  generateOptionalParamFlagsReader(type, os);
670	
671	  // Deserialize parameters conditionally based on file bytecode version.
672	  unsigned optionalBitIndex = 0;
673	  for (const auto &param : getSerializationOrder(type)) {
674	    bool isEvolved =
675	        !type.skipVersionCheck && param.sinceVersion != type.sinceVersion;
676	
677	    // Original parameters - always deserialize.
678	    if (!isEvolved) {
679	      // Optional params: template chooses format based on useUnifiedBitfield.
680	      if (param.usesOptionalTypeFlags) {
681	        os << formatv(R"(  {0} {1};
682	  if (!useUnifiedBitfield || (optionalFlags & (1ULL << {2}))) {{
683	)",
684	                      param.cppType, param.name, optionalBitIndex++);
685	        generateParameterDeserialization(
686	            param, os, "    ", /*declareVariable=*/false, "useUnifiedBitfield");
687	        os << R"(  }
688	)";
689	      } else {
690	        generateParameterDeserialization(
691	            param, os, "  ", /*declareVariable=*/true, "useUnifiedBitfield");
692	      }
693	      continue;
694	    }
695	
696	    // Evolved parameters - version-guarded deserialization.
697	    auto [majorStr, minorStr] = parseVersion(param.sinceVersion);
698	    std::string defaultValue =
699	        replaceTableGenPlaceholders(param.defaultValue, "&context");
700	
701	    // Optional params: conditionally read based on flag bit (template handles
702	    // runtime format).
703	    if (param.usesOptionalTypeFlags) {
704	      os << formatv(R"(  {0} {1};
705	  if (optionalFlags & (1ULL << {2})) {{
706	)",
707	                    param.cppType, param.name, optionalBitIndex++);
708	      generateParameterDeserialization(
709	          param, os, "    ", /*declareVariable=*/false, "useUnifiedBitfield");
710	      os << "  }\n";
711	      continue;
712	    }
713	
714	    // Non-optional params: initialize with default, conditionally override.
715	    os << formatv("  {0} {1} = {2};\n", param.cppType, param.name,
716	                  defaultValue);
717	    os << formatv(R"(
718	  if (fileVersion >= *BytecodeVersion::fromVersion({0}, {1}, 0)) {{
719	)",
720	                  majorStr, minorStr);
721	    generateParameterDeserialization(
722	        param, os, "    ", /*declareVariable=*/false, "useUnifiedBitfield");
723	    os << "  }\n";
724	  }
725	
726	  // Build constructor arguments.
727	  std::string args;
728	  for (const auto &param : type.parameters) {
729	    StringRef paramTypeRef(param.cppStorageType);
730	    if (paramTypeRef.contains("SmallVector<int64_t>"))
731	      args += ", ArrayRef<int64_t>(" + param.name + ")";
732	    else if (paramTypeRef.contains("SmallVector<int32_t>"))
733	      args += ", ArrayRef<int32_t>(" + param.name + ")";
734	    else
735	      args += ", " + param.name;
736	  }
737	
738	  os << formatv(R"(  
739	  result = {0}::getChecked(
740	      [&]() {{ return reader.emitError(); }, &context{1});
741	  return success(result);
742	}
743	)",
744	                type.qualifiedTypeName, args);
745	}
746	
747	void mlir::tblgen::generateTypeDeserializers(
748	    const BytecodeTypeStructure &structure, raw_ostream &os) {
749	  emitSourceFileHeader("Generated Type Deserialization Functions", os);
750	  generateBuiltinTypeDeserializers(structure, os);
751	  for (const auto &type : structure.cudaTileTypes)
752	    generateCudaTileTypeDeserializer(type, os);
753	}
754	
755	//===----------------------------------------------------------------------===//
756	// C++ Generator - Dispatch.
757	//===----------------------------------------------------------------------===//
758	
759	void mlir::tblgen::generateSerializerDispatch(
760	    const BytecodeTypeStructure &structure, raw_ostream &os) {
761	  emitSourceFileHeader("Generated Type Serialization Dispatch", os);
762	
763	  os << R"(return TypeSwitch<Type, LogicalResult>(type)
764	)";
765	
766	  // Built-in types.
767	  if (llvm::any_of(structure.builtinSerializableTypes,
768	                   [](auto &t) { return t.isInteger(); }))
769	    os << R"(    .Case<IntegerType>([&](auto concreteType) {
770	      return serializeIntegerType(concreteType, writer, config);
771	    })
772	)";
773	
774	  if (llvm::any_of(structure.builtinSerializableTypes,
775	                   [](auto &t) { return t.isFloat(); }))
776	    os << R"(    .Case<FloatType>([&](auto concreteType) {
777	      return serializeFloatType(concreteType, writer, config);
778	    })
779	)";
780	
781	  // CudaTile types.
782	  for (const auto &type : structure.cudaTileTypes)
783	    os << formatv(R"(    .Case<{0}>([&](auto concreteType) {{
784	      return serialize{1}(concreteType, writer, config);
785	    })
786	)",
787	                  type.qualifiedTypeName, type.typeName);
788	
789	  // FunctionType and default case.
790	  os << R"(    .Case<FunctionType>([&](auto concreteType) {
791	      return serializeFunctionType(concreteType, writer);
792	    })
793	    .Default([&](Type) {
794	      return emitError(UnknownLoc::get(type.getContext()),
795	                       "unsupported type in bytecode writer");
796	    });
797	)";
798	}
799	
800	void mlir::tblgen::generateDependentTypeRegistration(
801	    const BytecodeTypeStructure &structure, raw_ostream &os) {
802	  emitSourceFileHeader("Generated Dependent Type Registration", os);
803	
804	  for (const auto &type : structure.cudaTileTypes) {
805	    // Check if type has Type parameters that need registration.
806	    if (!llvm::any_of(type.parameters, [](const BytecodeTypeParameter &p) {
807	          return isTypeParameter(p.kind);
808	        }))
809	      continue;
810	
811	    // Generate registration for this type.
812	    os << formatv("if (auto concreteType = dyn_cast<{0}>(type)) {{\n",
813	                  type.qualifiedTypeName);
814	    for (const auto &param : type.parameters)
815	      if (isTypeParameter(param.kind))
816	        os << formatv(R"(  if (auto paramType = concreteType.{0}())
817	    getTypeIndex(paramType);
818	)",
819	                      param.accessorName);
820	
821	    os << "  return;\n}\n";
822	  }
823	}
824	
825	void mlir::tblgen::generateDeserializerDispatch(
826	    const BytecodeTypeStructure &structure, raw_ostream &os) {
827	  emitSourceFileHeader("Generated Type Deserialization Dispatch", os);
828	
829	  os << R"(switch (static_cast<TypeTag>(typeTag)) {
830	)";
831	
832	  // Built-in types.
833	  for (const auto &builtinType : structure.builtinSerializableTypes) {
834	    os << "case Bytecode::TypeTag::" << builtinType.enumName << ":\n";
835	    if (builtinType.isInteger())
836	      os << "  return parseIntegerType(typeTag, result, context, "
837	            "fileVersion);\n";
838	    else if (builtinType.isFloat())
839	      os << "  return parseFloatType(typeTag, result, context, fileVersion);\n";
840	  }
841	
842	  // CudaTile types.
843	  for (const auto &type : structure.cudaTileTypes)
844	    os << formatv(R"(case Bytecode::TypeTag::{0}:
845	  return parse{0}(reader, result);
846	)",
847	                  type.typeName);
848	
849	  // FunctionType and default.
850	  os << R"(case Bytecode::TypeTag::FunctionType:
851	  return parseFunctionType(reader, result);
852	default:
853	  return ::emitError(UnknownLoc::get(&context))
854	         << "unknown type tag: " << static_cast<int>(typeTag);
855	}
856	)";
857	}
